class AuthProvider extends ChangeNotifier {
  final AuthManager _authManager = AuthManager();
  bool _isInitialized = false;
  bool _isLoggedIn = false;
  Map<String, dynamic>? _userData;

  bool get isInitialized => _isInitialized;
  bool get isLoggedIn => _isLoggedIn;
  Map<String, dynamic>? get userData => _userData;
  String? get accessToken => _authManager.getAccessToken();
  String? get refreshToken => _authManager.getRefreshToken();

  Future<void> init() async {
    await _authManager.init();
    _isLoggedIn = _authManager.isLoggedIn();
    _userData = _authManager.getUserData();
    _isInitialized = true;
    notifyListeners();
  }

  Future<bool> login({
    required String accessToken,
    required String refreshToken,
    required Map<String, dynamic> userData,
    DateTime? tokenExpiry,
  }) async {
    final success = await _authManager.login(
      accessToken: accessToken,
      refreshToken: refreshToken,
      userData: userData,
      tokenExpiry: tokenExpiry,
    );

    if (success) {
      _isLoggedIn = true;
      _userData = userData;
      notifyListeners();
    }

    return success;
  }

  Future<bool> logout() async {
    final success = await _authManager.logout();

    if (success) {
      _isLoggedIn = false;
      _userData = null;
      notifyListeners();
    }

    return success;
  }

  Future<bool> updateAccessToken(String newAccessToken, {DateTime? tokenExpiry}) async {
    return await _authManager.updateAccessToken(newAccessToken, tokenExpiry: tokenExpiry);
  }

  Future<bool> updateUserData(Map<String, dynamic> userData) async {
    final success = await _authManager.updateUserData(userData);
    if (success) {
      _userData = userData;
      notifyListeners();
    }
    return success;
  }

  bool isTokenExpired() {
    return _authManager.isTokenExpired();
